// Time:  O(nlogr)
// Space: O(1)

// binary search, greedy
class Solution {
public:
    int minOperations(vector<int>& nums, int x, int y) {
        const auto& ceil_divide = [](int a, int b) {
            return (a + b - 1) / b;
        };

        const auto& check = [&](int total) {
            return accumulate(cbegin(nums), cend(nums), 0ll, [&](const auto& accu, const auto& v) {
                return accu + ceil_divide(max(v - min(ceil_divide(v, y), total) * y, 0), x - y);
            }) <= total;
        };

        int left = 1, right = ceil_divide(*max_element(cbegin(nums), cend(nums)), y);
        while (left <= right) {
            const int mid = left + (right - left) / 2;
            if (check(mid)) {
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }
};

# Time:  O(nlogr)
# Space: O(1)

# binary search, greedy
class Solution(object):
    def minOperations(self, nums, x, y):
        """
        :type nums: List[int]
        :type x: int
        :type y: int
        :rtype: int
        """
        def ceil_divide(a, b):
            return (a+b-1)//b

        def check(total):
            return sum(ceil_divide(max(v-min(ceil_divide(v, y), total)*y, 0), x-y) for v in nums) <= total

        left, right = 1, ceil_divide(max(nums), y)
        while left <= right:
            mid = left+(right-left)//2
            if check(mid):
                right = mid-1
            else:
                left = mid+1
        return left
